void ZopfliBlockSplitLZ77(const ZopfliOptions *options,
                          const ZopfliLZ77Store *lz77, size_t maxblocks,
                          size_t **splitpoints, size_t *npoints)
{
    size_t lstart, lend;
    size_t i;
    size_t llpos = 0;
    size_t numblocks = 1;
    unsigned char *done;
    double splitcost, origcost;

    if (lz77->size < 10)
        return; /* This code fails on tiny files. */

    done = (unsigned char *)malloc(lz77->size);
    if (!done)
        exit(-1); /* Allocation failed. */
    for (i = 0; i < lz77->size; i++)
        done[i] = 0;

    lstart = 0;
    lend = lz77->size;
    for (;;)
    {
        SplitCostContext c;

        if (maxblocks > 0 && numblocks >= maxblocks)
        {
            break;
        }

        c.lz77 = lz77;
        c.start = lstart;
        c.end = lend;
        assert(lstart < lend);
        llpos = FindMinimum(SplitCost, &c, lstart + 1, lend, &splitcost);

        assert(llpos > lstart);
        assert(llpos < lend);

        origcost = EstimateCost(lz77, lstart, lend);

        if (splitcost > origcost || llpos == lstart + 1 || llpos == lend)
        {
            done[lstart] = 1;
        }
        else
        {
            AddSorted(llpos, splitpoints, npoints);
            numblocks++;
        }

        if (!FindLargestSplittableBlock(
                lz77->size, done, *splitpoints, *npoints, &lstart, &lend))
        {
            break; /* No further split will probably reduce compression. */
        }

        if (lend - lstart < 10)
        {
            break;
        }
    }

    if (options->verbose)
    {
        PrintBlockSplitPoints(lz77, *splitpoints, *npoints);
    }

    free(done);
}

/*
Does blocksplitting on uncompressed data.
The output splitpoints are indices in the uncompressed bytes.

options: general program options.
in: uncompressed input data
instart: where to start splitting
inend: where to end splitting (not inclusive)
maxblocks: maximum amount of blocks to split into, or 0 for no limit
splitpoints: dynamic array to put the resulting split point coordinates into.
The coordinates are indices in the input array.
npoints: pointer to amount of splitpoints, for the dynamic array. The amount of
blocks is the amount of splitpoitns + 1.
*/
void ZopfliBlockSplit(const ZopfliOptions *options,
                      const unsigned char *in, size_t instart, size_t inend,
                      size_t maxblocks, size_t **splitpoints, size_t *npoints)
{
    size_t pos = 0;
    size_t i;
    ZopfliBlockState s;
    size_t *lz77splitpoints = 0;
    size_t nlz77points = 0;
    ZopfliLZ77Store store;
    ZopfliHash hash;
    ZopfliHash *h = &hash;

    ZopfliInitLZ77Store(in, &store);
    ZopfliInitBlockState(options, instart, inend, 0, &s);
    ZopfliAllocHash(ZOPFLI_WINDOW_SIZE, h);

    *npoints = 0;
    *splitpoints = 0;

    /* Unintuitively, Using a simple LZ77 method here instead of ZopfliLZ77Optimal
    results in better blocks. */
    ZopfliLZ77Greedy(&s, in, instart, inend, &store, h);

