4585	__CPROVER_requires(npoints <= 4)
4586	__CPROVER_requires(__CPROVER_is_fresh(done, lz77size * sizeof(*done)))
4587	__CPROVER_requires(__CPROVER_is_fresh(
4588	    splitpoints, (npoints == 0 ? 1 : npoints) * sizeof(*splitpoints)))
4589	__CPROVER_requires(__CPROVER_forall {
4590	    size_t k; (k < npoints) ==> splitpoints[k] < lz77size })
4591	__CPROVER_requires(__CPROVER_forall {
4592	    size_t j; (j < npoints && j + 1 < npoints)
4593	              ==> splitpoints[j] <= splitpoints[j + 1] })
4594	__CPROVER_requires(__CPROVER_is_fresh(lstart, sizeof(*lstart)))
4595	__CPROVER_requires(__CPROVER_is_fresh(lend, sizeof(*lend)))
4596	__CPROVER_assigns(*lstart, *lend)
4597	__CPROVER_ensures(__CPROVER_return_value == 0 || __CPROVER_return_value == 1)
